import React, { useEffect, useState } from "react";
import Sidebar from "../../components/Sidebar";
import { getFreelancers, getClients } from "../../api/api";

const ManageUsers = () => {
  const [activeTab, setActiveTab] = useState("freelancers");
  const [freelancers, setFreelancers] = useState([]);
  const [clients, setClients] = useState([]);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    fetchUsers();
  }, []);

  const fetchUsers = async () => {
    try {
      const freelancerRes = await getFreelancers();
      const clientRes = await getClients();

      setFreelancers(freelancerRes.data);
      setClients(clientRes.data);
      setLoading(false);
    } catch (error) {
      console.log(error);
      setLoading(false);
    }
  };

  const usersToShow =
    activeTab === "freelancers" ? freelancers : clients;

  return (
    <div className="flex bg-gray-100 min-h-screen">
      
      {/* ===== SIDEBAR ===== */}
      <Sidebar />

      {/* ===== MAIN CONTENT ===== */}
      <div className="flex-1 p-8">
        
        <h1 className="text-3xl font-bold mb-6">
          User Management
        </h1>

        {/* ===== TABS ===== */}
        <div className="flex gap-4 mb-6">
          <button
            onClick={() => setActiveTab("freelancers")}
            className={`px-4 py-2 rounded-lg ${
              activeTab === "freelancers"
                ? "bg-teal-600 text-white"
                : "bg-gray-200"
            }`}
          >
            Freelancers
          </button>

          <button
            onClick={() => setActiveTab("clients")}
            className={`px-4 py-2 rounded-lg ${
              activeTab === "clients"
                ? "bg-teal-600 text-white"
                : "bg-gray-200"
            }`}
          >
            Clients
          </button>
        </div>

        {/* ===== TABLE CARD ===== */}
        <div className="bg-white rounded-2xl shadow p-6">
          <h2 className="text-xl font-semibold mb-4">
            {activeTab === "freelancers"
              ? "All Freelancers"
              : "All Clients"}
          </h2>

          {loading ? (
            <p>Loading...</p>
          ) : (
            <table className="w-full text-left">
              <thead>
                <tr className="border-b text-gray-600">
                  <th className="py-3">Name</th>
                  <th>Specialization</th>
                  <th>Rating</th>
                  <th>Projects</th>
                  <th>Earnings</th>
                  <th>Status</th>
                </tr>
              </thead>

              <tbody>
                {usersToShow.length > 0 ? (
                  usersToShow.map((user) => (
                    <tr
                      key={user.id}
                      className="border-b hover:bg-gray-50"
                    >
                      <td className="py-3 font-medium">
                        {user.name}
                      </td>

                      <td>
                        {user.specialization || "—"}
                      </td>

                      <td className="text-yellow-500">
                        ⭐ {user.rating || "4.8"}
                      </td>

                      <td>{user.projects || 20}</td>

                      <td>
                        $
                        {user.earnings
                          ? user.earnings.toLocaleString("en-US")
                          : "25,000"}
                      </td>

                      <td>
                        <span
                          className={`px-3 py-1 rounded-full text-sm ${
                            user.status === "busy"
                              ? "bg-yellow-100 text-yellow-600"
                              : "bg-green-100 text-green-600"
                          }`}
                        >
                          {user.status || "active"}
                        </span>
                      </td>
                    </tr>
                  ))
                ) : (
                  <tr>
                    <td colSpan="6" className="text-center py-6">
                      No Users Found
                    </td>
                  </tr>
                )}
              </tbody>
            </table>
          )}
        </div>

      </div>
    </div>
  );
};

export default ManageUsers;
